public class Scope {
    static int x = 10;

    static int compute(int x) {
        return x * 2 + Scope.x;
    }

    static void show(int val) {
        int x = 99;
        System.out.println(val + x);
    }

    public static void main(String[] args) {
        System.out.println(compute(5));
        show(compute(3));
    }
}
